#!/usr/bin/env bash
set -uo pipefail

# Generated by analysis/phase2_preflight.py.
# HPO jobs only. Jobs continue independently after a failure.
DEVICE="${DEVICE:-cuda:0}"
failures=0

run_job() {
  local log="$1"
  shift
  mkdir -p "$(dirname "$log")"
  if ! "$@" >"$log" 2>&1; then
    printf "FAILED: %s (see %s)\n" "$*" "$log" >&2
    failures=$((failures + 1))
  fi
}

run_hpo_job() {
  local log="$1" model="$2"
  shift 2
  local ceiling_args=()
  if [[ "$model" =~ ^(tabr|modernnca)$ && -n "${RETRIEVAL_COMPUTE_CEILING_HOURS:-}" ]]; then
    ceiling_args=(--compute-ceiling-hours "$RETRIEVAL_COMPUTE_CEILING_HOURS")
  fi
  run_job "$log" "$@" "${ceiling_args[@]}"
}

